import React from 'react';
import { useNavigate } from 'react-router-dom';

function Apresentacao() {
  const navigate = useNavigate();

  return (
    <div style={{ padding: '20px', textAlign: 'center' }}>
      <h2>Integrantes da Dupla</h2>
      <div style={{ border: '1px solid #ccc', padding: '15px', borderRadius: '8px', margin: '10px auto', maxWidth: '400px' }}>
        <h3>Lucas Gabriel</h3>
        <p><strong>Formação:</strong> Engenharia de Software (5º Período)</p>
        <p><strong>Interesses:</strong> Desenvolvimento Web e Hardware de PC</p>
      </div>
      {/* Adicione os dados do seu colega abaixo se houver */}
      <button onClick={() => navigate('/')} style={{ marginTop: '20px' }}>
        Voltar para Home
      </button>
    </div>
  );
}

export default Apresentacao;
